// store.ts
type Price = { symbol: string; bid: number; ask: number; ts: number };

class TickerStore {
  private prices = new Map<string, Price>();
  private listeners = new Map<string, Set<() => void>>();

  subscribe(symbol: string, cb: () => void) {
    if (!this.listeners.has(symbol)) this.listeners.set(symbol, new Set());
    this.listeners.get(symbol)!.add(cb);
    return () => this.listeners.get(symbol)?.delete(cb);
  }

  getSnapshot(symbol: string): Price | undefined {
    return this.prices.get(symbol);
  }

  ingest(p: Price) {
    this.prices.set(p.symbol, p);
    this.listeners.get(p.symbol)?.forEach((cb) => cb());
  }
}

export const tickerStore = new TickerStore();

// useTickerPrice.ts
import { useSyncExternalStore } from 'react';
export function useTickerPrice(symbol: string) {
  return useSyncExternalStore(
    (cb) => tickerStore.subscribe(symbol, cb),
    () => tickerStore.getSnapshot(symbol),
    () => undefined,
  );
}

// TickerCell.tsx
export function TickerCell({ symbol }: { symbol: string }) {
  const price = useTickerPrice(symbol);
  if (!price) return <td>--</td>;
  return <td>{price.bid.toFixed(2)} / {price.ask.toFixed(2)}</td>;
}

// signals.ts
import { signal, computed, type Signal } from '@preact/signals-react';
const priceSignals = new Map<string, Signal<{ bid: number; ask: number } | null>>();

export function getPriceSignal(symbol: string) {
  let s = priceSignals.get(symbol);
  if (!s) {
    s = signal(null);
    priceSignals.set(symbol, s);
  }
  return s;
}

export function ingest(p: { symbol: string; bid: number; ask: number }) {
  getPriceSignal(p.symbol).value = { bid: p.bid, ask: p.ask };
}

