// Reviews.tsx - Client Component (whole feature)
'use client';
import { useState, useOptimistic } from 'react';
import { voteHelpful, fetchReviews } from '@/actions/reviews';

export function Reviews({ productId, initial }: { productId: string; initial: Review[] }) {
  const [page, setPage] = useState(1);
  const [reviews, setReviews] = useState(initial);
  const [optimistic, addOptimistic] = useOptimistic(
    reviews,
    (state, vote: { id: string }) =>
      state.map((r) => (r.id === vote.id ? { ...r, helpful: r.helpful + 1 } : r)),
  );

  const onVote = async (id: string) => {
    addOptimistic({ id });
    await voteHelpful(id);
  };

  const onNext = async () => {
    const next = await fetchReviews(productId, page + 1);
    setReviews(next);
    setPage(page + 1);
  };

  return (
    <section>
      {optimistic.map((r) => (
        <article key={r.id} className="border-b py-3">
          <p>{r.text}</p>
          <button onClick={() => onVote(r.id)}>Helpful ({r.helpful})</button>
        </article>
      ))}
      <button onClick={onNext}>Next page</button>
    </section>
  );
}

// WidgetShell.tsx
import { Suspense } from 'react';
import { QueryErrorResetBoundary } from '@tanstack/react-query';
import { ErrorBoundary } from 'react-error-boundary';

export function WidgetShell({ children, name }: { children: React.ReactNode; name: string }) {
  return (
    <QueryErrorResetBoundary>
      {({ reset }) => (
        <ErrorBoundary
          onReset={reset}
          fallbackRender={({ resetErrorBoundary }) => (
            <div className="rounded-lg border border-red-200 p-4">
              <p>Failed to load {name}</p>
              <button onClick={resetErrorBoundary} className="mt-2 text-sm underline">Retry</button>
            </div>
          )}
        >
          <Suspense fallback={<div className="h-48 animate-pulse rounded-lg bg-zinc-100" />}>
            {children}
          </Suspense>
        </ErrorBoundary>
      )}
    </QueryErrorResetBoundary>
  );
}

