import { useQuery } from '@tanstack/react-query';

export function RevenueWidget({ orgId }: { orgId: string }) {
  const { data, isLoading, isError, refetch } = useQuery({
    queryKey: ['revenue', orgId],
    queryFn: () => fetch(`/api/revenue/${orgId}`).then((r) => r.json()),
  });

  if (isLoading) return <div className="h-48 animate-pulse rounded-lg bg-zinc-100" />;
  if (isError)
    return (
      <div className="rounded-lg border border-red-200 p-4">
        <p>Failed to load Revenue</p>
        <button onClick={() => refetch()} className="mt-2 text-sm underline">Retry</button>
      </div>
    );

  return (
    <div className="rounded-lg border p-4">
      <h3 className="text-sm text-zinc-600">Revenue</h3>
      <p className="mt-2 text-3xl font-semibold">${data.total.toLocaleString()}</p>
    </div>
  );
}

