type AsyncOperation =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success' }
  | { status: 'error'; message: string };

type WidgetState<T> = {
  operation: AsyncOperation;
  data?: T; // cached, survives state transitions
};

function reducer<T>(state: WidgetState<T>, action: WidgetAction<T>): WidgetState<T> {
  switch (action.type) {
    case 'fetch_start':
      return { ...state, operation: { status: 'loading' } };
    case 'fetch_success':
      return { operation: { status: 'success' }, data: action.data };
    case 'fetch_error':
      return { ...state, operation: { status: 'error', message: action.message } };
  }
}

type WidgetAction<T> =
  | { type: 'fetch_start' }
  | { type: 'fetch_success'; data: T }
  | { type: 'fetch_error'; message: string };

export function Widget<T>({ state, render }: { state: WidgetState<T>; render: (data: T) => React.ReactNode }) {
  return (
    <div className="relative">
      {state.operation.status === 'loading' && <div className="absolute right-2 top-2"><Spinner /></div>}
      {state.operation.status === 'error' && (
        <div className="rounded bg-red-50 p-2 text-sm text-red-700">{state.operation.message}</div>
      )}
      {state.data ? render(state.data) : state.operation.status === 'idle' ? <Placeholder /> : <Skeleton />}
    </div>
  );
}

type WidgetState<T> =
  | { kind: 'idle' }
  | { kind: 'loading' }
  | { kind: 'success'; data: T }
  | { kind: 'error'; message: string };

export function Widget<T>({ state, render }: { state: WidgetState<T>; render: (data: T) => React.ReactNode }) {
  switch (state.kind) {
    case 'idle': return <Placeholder />;
    case 'loading': return <Skeleton />;
    case 'success': return <>{render(state.data)}</>;
    case 'error': return <div className="rounded bg-red-50 p-2">{state.message}</div>;
  }
}

'use client';
import { useOptimistic, useState, useTransition } from 'react';

type Note = { id: string; title: string };

export function NoteTitle({ note, onRename }: { note: Note; onRename: (title: string) => Promise<{ ok: true } | { ok: false; error: string }> }) {
  const [pending, startTransition] = useTransition();
  const [optimisticTitle, setOptimisticTitle] = useOptimistic(
    note.title,
    (_current, nextTitle: string) => nextTitle,
  );
  const [error, setError] = useState<string | null>(null);

  const submit = (next: string) => {
    setError(null);
    startTransition(async () => {
      setOptimisticTitle(next);
      const result = await onRename(next);
      if (!result.ok) {
        setError(result.error);
        throw new Error(result.error); // triggers useOptimistic revert
      }
    });
  };

  return (
    <div>
      <input
        defaultValue={optimisticTitle}
        onBlur={(e) => submit(e.currentTarget.value)}
        className={`border-b ${pending ? 'opacity-70' : ''} ${error ? 'border-red-500' : ''}`}
      />
      {pending && <span className="ml-2 text-xs text-zinc-500">Saving...</span>}
      {error && <span className="ml-2 text-xs text-red-600">{error}</span>}
    </div>
  );
}

'use client';
import { useState } from 'react';

type Note = { id: string; title: string };

export function NoteTitle({ note, onRename }: { note: Note; onRename: (title: string) => Promise<{ ok: true } | { ok: false; error: string }> }) {
  const [draft, setDraft] = useState(note.title);
  const [pending, setPending] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const submit = async () => {
    if (draft === note.title) return;
    setPending(true);
    setError(null);
    const result = await onRename(draft);
    setPending(false);
    if (!result.ok) setError(result.error);
  };

  return (
    <div>
      <input
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onBlur={submit}
        disabled={pending}
        className={`border-b ${pending ? 'opacity-70' : ''} ${error ? 'border-red-500' : ''}`}
      />
      {pending && <span className="ml-2 text-xs text-zinc-500">Saving...</span>}
      {error && <span className="ml-2 text-xs text-red-600">{error}</span>}
    </div>
  );
}

