// scripts/drift-report.ts (CI job)
import { createHash } from 'crypto';
import { readFile } from 'fs/promises';

async function checkDrift(component: string, appDir: string) {
  const local = await readFile(`${appDir}/${component}.tsx`, 'utf8');
  const remote = await fetch(`${REGISTRY}/${component}.tsx`).then((r) => r.text());
  const localHash = createHash('sha256').update(local).digest('hex');
  const remoteHash = createHash('sha256').update(remote).digest('hex');
  if (localHash !== remoteHash) {
    console.log(`${component} in ${appDir} has drifted from registry`);
  }
}

