'use client';
import { useForm, FormProvider, useFormContext } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useState } from 'react';

const kycSchema = z.discriminatedUnion('region', [
  z.object({
    region: z.literal('us'),
    fullName: z.string().min(1),
    ssn: z.string().regex(/^\d{3}-\d{2}-\d{4}$/),
    address: z.string().min(1),
  }),
  z.object({
    region: z.literal('eu'),
    fullName: z.string().min(1),
    vatId: z.string().regex(/^[A-Z]{2}\d+$/),
    address: z.string().min(1),
  }),
]);

type KycValues = z.infer<typeof kycSchema>;

export function KycFlow() {
  const [step, setStep] = useState(0);
  const methods = useForm<KycValues>({
    resolver: zodResolver(kycSchema),
    defaultValues: { region: 'us' },
    mode: 'onBlur',
  });

  return (
    <FormProvider {...methods}>
      <form onSubmit={methods.handleSubmit(onSubmit)} className="space-y-6">
        {step === 0 && <RegionStep onNext={() => setStep(1)} />}
        {step === 1 && <IdentityStep onBack={() => setStep(0)} onNext={() => setStep(2)} />}
        {step === 2 && <ReviewStep onBack={() => setStep(1)} />}
      </form>
    </FormProvider>
  );
}

function IdentityStep({ onBack, onNext }: { onBack: () => void; onNext: () => void }) {
  const { register, watch, formState: { errors }, trigger } = useFormContext<KycValues>();
  const region = watch('region');

  const next = async () => {
    const fields = region === 'us' ? ['fullName', 'ssn'] as const : ['fullName', 'vatId'] as const;
    const ok = await trigger(fields);
    if (ok) onNext();
  };

  return (
    <div className="space-y-4">
      <input {...register('fullName')} placeholder="Full name" className="w-full rounded border p-2" />
      {errors.fullName && <p className="text-sm text-red-600">{errors.fullName.message}</p>}
      {region === 'us' && (
        <>
          <input {...register('ssn')} placeholder="SSN" className="w-full rounded border p-2" />
          {'ssn' in errors && errors.ssn && <p className="text-sm text-red-600">{errors.ssn.message}</p>}
        </>
      )}
      {region === 'eu' && (
        <>
          <input {...register('vatId')} placeholder="VAT ID" className="w-full rounded border p-2" />
          {'vatId' in errors && errors.vatId && <p className="text-sm text-red-600">{errors.vatId.message}</p>}
        </>
      )}
      <div className="flex justify-between">
        <button type="button" onClick={onBack}>Back</button>
        <button type="button" onClick={next}>Next</button>
      </div>
    </div>
  );
}

async function onSubmit(values: KycValues) {
  await fetch('/api/kyc', { method: 'POST', body: JSON.stringify(values) });
}

'use client';
import { useForm } from '@tanstack/react-form';
import { z } from 'zod';

const kycSchema = z.object({
  region: z.enum(['us', 'eu']),
  fullName: z.string().min(1),
  ssn: z.string().regex(/^\d{3}-\d{2}-\d{4}$/).optional(),
  vatId: z.string().regex(/^[A-Z]{2}\d+$/).optional(),
});

export function KycFlow() {
  const form = useForm({
    defaultValues: { region: 'us' as 'us' | 'eu', fullName: '', ssn: '', vatId: '' },
    onSubmit: async ({ value }) => {
      await fetch('/api/kyc', { method: 'POST', body: JSON.stringify(value) });
    },
  });

  return (
    <form.Provider>
      <form
        onSubmit={(e) => {
          e.preventDefault();
          form.handleSubmit();
        }}
        className="space-y-4"
      >
        <form.Field
          name="region"
          children={(field) => (
            <select value={field.state.value} onChange={(e) => field.handleChange(e.target.value as 'us' | 'eu')}>
              <option value="us">United States</option>
              <option value="eu">Europe</option>
            </select>
          )}
        />
        <form.Field
          name="fullName"
          validators={{ onBlur: ({ value }) => (value ? undefined : 'Required') }}
          children={(field) => (
            <input
              value={field.state.value}
              onChange={(e) => field.handleChange(e.target.value)}
              onBlur={field.handleBlur}
              className="w-full rounded border p-2"
            />
          )}
        />
        <form.Subscribe
          selector={(state) => state.values.region}
          children={(region) =>
            region === 'us' ? (
              <form.Field name="ssn" children={(field) => (
                <input value={field.state.value ?? ''} onChange={(e) => field.handleChange(e.target.value)} />
              )} />
            ) : (
              <form.Field name="vatId" children={(field) => (
                <input value={field.state.value ?? ''} onChange={(e) => field.handleChange(e.target.value)} />
              )} />
            )
          }
        />
        <button type="submit">Submit</button>
      </form>
    </form.Provider>
  );
}

