'use client';
import { ErrorBoundary } from 'react-error-boundary';
import * as Sentry from '@sentry/react';

type Criticality = 'critical' | 'auxiliary';

export function WidgetBoundary({
  name,
  criticality,
  fallback,
  children,
}: {
  name: string;
  criticality: Criticality;
  fallback?: React.ReactNode;
  children: React.ReactNode;
}) {
  return (
    <ErrorBoundary
      fallbackRender={({ error, resetErrorBoundary }) => (
        <div className="rounded-lg border border-zinc-200 bg-zinc-50 p-4">
          <p className="text-sm text-zinc-700">
            {name} unavailable
            {criticality === 'critical' && ' - other widgets continue working'}
          </p>
          <button onClick={resetErrorBoundary} className="mt-2 text-xs underline">Retry</button>
        </div>
      )}
      onError={(error, info) => {
        Sentry.captureException(error, {
          tags: { widget: name, criticality },
          contexts: { react: { componentStack: info.componentStack } },
          level: criticality === 'critical' ? 'error' : 'warning',
        });
      }}
    >
      {children}
    </ErrorBoundary>
  );
}

