'use client';
import { ErrorBoundary } from 'react-error-boundary';
import * as Sentry from '@sentry/react';

// Critical wrapper - explicit opt-in
export function Critical({ name, children }: { name: string; children: React.ReactNode }) {
  return (
    <ErrorBoundary
      fallbackRender={({ resetErrorBoundary }) => (
        <div className="rounded-lg border border-red-300 bg-red-50 p-4">
          <p>{name} unavailable. Other widgets remain operational.</p>
          <button onClick={resetErrorBoundary}>Retry</button>
        </div>
      )}
      onError={(error) => Sentry.captureException(error, { tags: { critical: true, widget: name } })}
    >
      {children}
    </ErrorBoundary>
  );
}

// Page-level boundary (default for everything else)
export function PageBoundary({ children }: { children: React.ReactNode }) {
  return (
    <ErrorBoundary
      fallbackRender={({ resetErrorBoundary }) => (
        <div className="flex h-screen flex-col items-center justify-center">
          <h2>Something went wrong</h2>
          <button onClick={resetErrorBoundary}>Reload page</button>
        </div>
      )}
      onError={(error) => Sentry.captureException(error, { level: 'fatal' })}
    >
      {children}
    </ErrorBoundary>
  );
}

