type Item = { id: string; name: string; email: string; status: 'active' | 'inactive' };

export function UserGrid({ items }: { items: Item[] }) {
  const [selection, setSelection] = useState<Selection>(new Set());
  const [sortColumn, setSortColumn] = useState<keyof Item>('name');
  const [sortDirection, setSortDirection] = useState<'ascending' | 'descending'>('ascending');

  const sorted = useMemo(() => {
    return [...items].sort((a, b) => {
      const cmp = String(a[sortColumn]).localeCompare(String(b[sortColumn]));
      return sortDirection === 'ascending' ? cmp : -cmp;
    });
  }, [items, sortColumn, sortDirection]);

  return (
    <Table
      aria-label="Users"
      selectionMode="multiple"
      selectedKeys={selection}
      onSelectionChange={setSelection}
      sortDescriptor={{ column: sortColumn, direction: sortDirection }}
      onSortChange={({ column, direction }) => {
        setSortColumn(column as keyof Item);
        setSortDirection(direction);
      }}
      className="w-full border-collapse"
    >
      <TableHeader>
        <Column id="name" allowsSorting isRowHeader>Name</Column>
        <Column id="email" allowsSorting>Email</Column>
        <Column id="status" allowsSorting>Status</Column>
      </TableHeader>
      <TableBody items={sorted}>
        {(item) => (
          <Row id={item.id}>
            <Cell>{item.name}</Cell>
            <Cell>{item.email}</Cell>
            <Cell>
              <span className={item.status === 'active' ? 'text-emerald-600' : 'text-zinc-500'}>
                {item.status}
              </span>
            </Cell>
          </Row>
        )}
      </TableBody>
    </Table>
  );
}

'use client';
import { useState, useMemo } from 'react';

type Item = { id: string; name: string; email: string; status: 'active' | 'inactive' };

export function UserTable({ items }: { items: Item[] }) {
  const [sortColumn, setSortColumn] = useState<keyof Item>('name');
  const [direction, setDirection] = useState<'asc' | 'desc'>('asc');
  const [selected, setSelected] = useState<Set<string>>(new Set());

  const sorted = useMemo(() => {
    return [...items].sort((a, b) => {
      const cmp = String(a[sortColumn]).localeCompare(String(b[sortColumn]));
      return direction === 'asc' ? cmp : -cmp;
    });
  }, [items, sortColumn, direction]);

  const toggleSort = (col: keyof Item) => {
    if (col === sortColumn) setDirection((d) => (d === 'asc' ? 'desc' : 'asc'));
    else { setSortColumn(col); setDirection('asc'); }
  };

  return (
    <table className="w-full border-collapse" aria-label="Users">
      <thead>
        <tr>
          <th scope="col" aria-sort={sortColumn === 'name' ? (direction === 'asc' ? 'ascending' : 'descending') : 'none'}>
            <button onClick={() => toggleSort('name')} className="font-medium">Name</button>
          </th>
          <th scope="col" aria-sort={sortColumn === 'email' ? (direction === 'asc' ? 'ascending' : 'descending') : 'none'}>
            <button onClick={() => toggleSort('email')} className="font-medium">Email</button>
          </th>
          <th scope="col">Status</th>
        </tr>
      </thead>
      <tbody style={{ contentVisibility: 'auto' as any, containIntrinsicSize: '40px' } as React.CSSProperties}>
        {sorted.map((item) => (
          <tr
            key={item.id}
            aria-selected={selected.has(item.id)}
            onClick={() => setSelected((s) => {
              const next = new Set(s);
              if (next.has(item.id)) next.delete(item.id); else next.add(item.id);
              return next;
            })}
          >
            <th scope="row">{item.name}</th>
            <td>{item.email}</td>
            <td>
              <span className={item.status === 'active' ? 'text-emerald-600' : 'text-zinc-500'}>
                {item.status}
              </span>
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

