import { z } from 'zod';

// Path union - autocomplete + compile-time enforcement
type Path =
  | '/users/:id'
  | '/users/:id/posts'
  | '/users/:id/posts/:postId'
  | '/posts/:id'
  | '/posts/:id/comments';

// Params schema per path
const pathParams = {
  '/users/:id': z.object({ id: z.string() }),
  '/users/:id/posts': z.object({ id: z.string() }),
  '/users/:id/posts/:postId': z.object({ id: z.string(), postId: z.string() }),
  '/posts/:id': z.object({ id: z.string() }),
  '/posts/:id/comments': z.object({ id: z.string() }),
} satisfies Record<Path, z.ZodSchema>;

type PathParams<P extends Path> = z.infer<typeof pathParams[P]>;

function buildUrl<P extends Path>(path: P, params: PathParams<P>): string {
  // Runtime validation
  pathParams[path].parse(params);
  // Substitute
  return path.replace(/:(\w+)/g, (_, key) => {
    const value = (params as Record<string, string>)[key];
    if (value === undefined) throw new Error(`Missing param: ${key}`);
    return encodeURIComponent(value);
  });
}

// Usage - autocomplete on path, type-checked params
