// API client uses it
export async function get<P extends Path>(
  path: P,
  params: PathParams<P>,
  responseSchema: z.ZodSchema,
): Promise<z.infer<typeof responseSchema>> {
  const url = buildUrl(path, params);
  const res = await fetch(url);
  return responseSchema.parse(await res.json());
}

import { z } from 'zod';

// Extract param names from path pattern
type ExtractParams<P extends string> =
  P extends `${string}:${infer Param}/${infer Rest}`
    ? Param | ExtractParams<Rest>
    : P extends `${string}:${infer Param}`
    ? Param
    : never;

type ParamsOf<P extends string> = { [K in ExtractParams<P>]: string };

// Use it
function buildUrl<P extends string>(path: P, params: ParamsOf<P>): string {
  return path.replace(/:(\w+)/g, (_, key) => {
    return encodeURIComponent((params as Record<string, string>)[key]!);
  });
}

