// csv.worker.ts
import Papa from 'papaparse';

type RowsMessage = { type: 'rows'; rows: Record<string, string>[] };
type DoneMessage = { type: 'done'; total: number };
type ErrorMessage = { type: 'error'; error: string };
export type WorkerMessage = RowsMessage | DoneMessage | ErrorMessage;

self.addEventListener('message', (e: MessageEvent<{ file: File }>) => {
  let count = 0;
  let batch: Record<string, string>[] = [];

  Papa.parse<Record<string, string>>(e.data.file, {
    header: true,
    worker: false, // we ARE the worker
    step: (result) => {
      batch.push(result.data);
      count++;
      if (batch.length >= 1000) {
        self.postMessage({ type: 'rows', rows: batch } satisfies WorkerMessage);
        batch = [];
      }
    },
    complete: () => {
      if (batch.length) self.postMessage({ type: 'rows', rows: batch } satisfies WorkerMessage);
      self.postMessage({ type: 'done', total: count } satisfies WorkerMessage);
    },
    error: (err) => {
      self.postMessage({ type: 'error', error: err.message } satisfies WorkerMessage);
    },
  });
});

// useCsvParse.ts
import { useState, useCallback, useEffect, useRef } from 'react';
import type { WorkerMessage } from './csv.worker';

export function useCsvParse() {
  const [rows, setRows] = useState<Record<string, string>[]>([]);
  const [progress, setProgress] = useState({ count: 0, done: false });
  const [error, setError] = useState<string | null>(null);
  const workerRef = useRef<Worker | null>(null);

  const parse = useCallback((file: File) => {
    setRows([]);
    setProgress({ count: 0, done: false });
    setError(null);
    workerRef.current?.terminate();
    const worker = new Worker(new URL('./csv.worker.ts', import.meta.url), { type: 'module' });
    workerRef.current = worker;
    worker.addEventListener('message', (e: MessageEvent<WorkerMessage>) => {
      const msg = e.data;
      if (msg.type === 'rows') {
        setRows((r) => r.concat(msg.rows));
        setProgress((p) => ({ ...p, count: p.count + msg.rows.length }));
      } else if (msg.type === 'done') {
        setProgress((p) => ({ ...p, done: true }));
        worker.terminate();
      } else {
        setError(msg.error);
        worker.terminate();
      }
    });
    worker.postMessage({ file });
  }, []);

  useEffect(() => () => workerRef.current?.terminate(), []);

  return { rows, progress, error, parse };
}

// CsvUpload.tsx
export function CsvUpload() {
  const { rows, progress, error, parse } = useCsvParse();
  return (
    <div>
      <input type="file" accept=".csv" onChange={(e) => e.target.files?.[0] && parse(e.target.files[0])} />
      <p>Parsed {progress.count} rows {progress.done ? '(done)' : '...'}</p>
      {error && <p className="text-red-600">{error}</p>}
      {/* Render rows */}
    </div>
  );
}

// index.worker.ts
import * as Comlink from 'comlink';
import FlexSearch from 'flexsearch';

const api = {
  async buildIndex(records: Array<{ id: string; text: string }>) {
    const index = new FlexSearch.Index({ tokenize: 'forward' });
    for (const r of records) {
      index.add(r.id, r.text);
    }
    return index.export(() => undefined); // returns serialized index
  },
};

export type IndexWorkerApi = typeof api;
Comlink.expose(api);

// useSearchIndex.ts
import * as Comlink from 'comlink';
import { useEffect, useState } from 'react';
import FlexSearch from 'flexsearch';
import type { IndexWorkerApi } from './index.worker';

export function useSearchIndex(records: Array<{ id: string; text: string }>) {
  const [index, setIndex] = useState<FlexSearch.Index | null>(null);

  useEffect(() => {
    const worker = new Worker(new URL('./index.worker.ts', import.meta.url), { type: 'module' });
    const api = Comlink.wrap<IndexWorkerApi>(worker);
    let cancelled = false;
    api.buildIndex(records).then((exported) => {
      if (cancelled) return;
      const idx = new FlexSearch.Index({ tokenize: 'forward' });
      idx.import('', exported as string);
      setIndex(idx);
      worker.terminate();
    });
    return () => { cancelled = true; worker.terminate(); };
  }, [records]);

  return index;
}

// SearchBar.tsx - queries run on main thread for speed
export function SearchBar({ records }: { records: Array<{ id: string; text: string }> }) {
  const index = useSearchIndex(records);
  const [query, setQuery] = useState('');
  const results = useMemo(() => {
    if (!index || !query) return [];
    return index.search(query); // <5ms in-thread
  }, [index, query]);
  return (
    <div>
      <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search..." />
      <ul>{results.map((id) => <li key={String(id)}>{id}</li>)}</ul>
    </div>
  );
}

