// store.ts
type Shape = { id: string; x: number; y: number; width: number; height: number; fill: string };
type State = { shapes: Record<string, Shape>; selectedId: string | null };

class WhiteboardStore {
  private state: State = { shapes: {}, selectedId: null };
  private listeners = new Set<() => void>();

  getState = (): State => this.state;
  subscribe = (cb: () => void) => {
    this.listeners.add(cb);
    return () => this.listeners.delete(cb);
  };
  private notify = () => this.listeners.forEach((cb) => cb());

  updateShape(id: string, patch: Partial<Shape>) {
    const current = this.state.shapes[id];
    if (!current) return;
    this.state = {
      ...this.state,
      shapes: { ...this.state.shapes, [id]: { ...current, ...patch } },
    };
    this.notify();
  }

  addShape(shape: Shape) {
    this.state = { ...this.state, shapes: { ...this.state.shapes, [shape.id]: shape } };
    this.notify();
  }
}

export const store = new WhiteboardStore();

