import { createContext, useContextSelector } from 'use-context-selector';
import { useState, useCallback } from 'react';

type Shape = { id: string; x: number; y: number; width: number; height: number; fill: string };
type State = {
  shapes: Record<string, Shape>;
  selectedId: string | null;
  updateShape: (id: string, patch: Partial<Shape>) => void;
  addShape: (shape: Shape) => void;
};

const WhiteboardContext = createContext<State | null>(null);

export function WhiteboardProvider({ children }: { children: React.ReactNode }) {
  const [shapes, setShapes] = useState<Record<string, Shape>>({});
  const [selectedId, setSelectedId] = useState<string | null>(null);

  const updateShape = useCallback((id: string, patch: Partial<Shape>) => {
    setShapes((s) => ({ ...s, [id]: { ...s[id], ...patch } }));
  }, []);

  const addShape = useCallback((shape: Shape) => {
    setShapes((s) => ({ ...s, [shape.id]: shape }));
  }, []);

  return (
    <WhiteboardContext.Provider value={{ shapes, selectedId, updateShape, addShape }}>
      {children}
    </WhiteboardContext.Provider>
  );
}

export function useShape(id: string) {
  return useContextSelector(WhiteboardContext, (s) => s?.shapes[id]);
}

export function useUpdateShape() {
  return useContextSelector(WhiteboardContext, (s) => s?.updateShape);
}

