  if (!shape) return null;
  return (
    <rect
      x={shape.x}
      y={shape.y}
      width={shape.width}
      height={shape.height}
      fill={shape.fill}
      onMouseDown={() => update?.(id, { fill: '#3b82f6' })}
    />
  );
}

