import { createRoot, type Root } from 'react-dom/client';
import { PortalApp } from './app';
import widgetCss from './widget.css?inline';

class PortalWidgetElement extends HTMLElement {
  private root: Root | null = null;
  private styleSheet: CSSStyleSheet | null = null;

  static observedAttributes = ['customer-id', 'theme'];

  connectedCallback() {
    const shadow = this.attachShadow({ mode: 'open' });

    // Inject styles via constructable stylesheet
    this.styleSheet = new CSSStyleSheet();
    this.styleSheet.replaceSync(widgetCss);
    shadow.adoptedStyleSheets = [this.styleSheet];

    // Mount React into shadow
    const mountPoint = document.createElement('div');
    shadow.appendChild(mountPoint);
    this.root = createRoot(mountPoint);
    this.render();
  }

  attributeChangedCallback() {
    this.render();
  }

  disconnectedCallback() {
    this.root?.unmount();
    this.root = null;
  }

  private render() {
    this.root?.render(
      <PortalApp
        customerId={this.getAttribute('customer-id') ?? ''}
        theme={(this.getAttribute('theme') as 'light' | 'dark') ?? 'light'}
      />,
    );
  }
}

