  @property() theme: 'light' | 'dark' = 'light';
  @state() private tab: 'orders' | 'invoices' = 'orders';
  @state() private data: unknown = null;
  @state() private loading = false;

  protected willUpdate(changed: PropertyValues) {
    if (changed.has('customerId') || changed.has('tab')) {
      this.fetchData();
    }
  }

  private async fetchData() {
    this.loading = true;
    const res = await fetch(`/api/${this.tab}?customer=${this.customerId}`);
    this.data = await res.json();
    this.loading = false;
  }

