        <nav>
          <button
            class=${this.tab === 'orders' ? 'active' : ''}
            @click=${() => (this.tab = 'orders')}
          >Orders</button>
          <button
            class=${this.tab === 'invoices' ? 'active' : ''}
            @click=${() => (this.tab = 'invoices')}
          >Invoices</button>
        </nav>
        ${this.loading ? html`<p>Loading...</p>` : html`<pre>${JSON.stringify(this.data, null, 2)}</pre>`}
      </div>
    `;
  }
}

