async function profileFlow() {
  const browser = await chromium.launch();
  const page = await browser.newPage();
  const client = await page.context().newCDPSession(page);
  await client.send('Profiler.enable');
  await client.send('Profiler.start');

  await page.goto('http://localhost:3000');
  await page.click('[data-testid="open-dialog"]');
  await page.fill('[data-testid="search-input"]', 'test query');
  await page.click('[data-testid="submit"]');

  const { profile } = await client.send('Profiler.stop');
  const components = analyzeReactComponents(profile);
  const hot = components.filter((c) => c.renderCount > 20);
  if (hot.length) {
    console.log('Components rendering >20 times:');
    hot.forEach((c) => console.log(`  ${c.name}: ${c.renderCount} renders`));
    process.exit(1);
  }
  await browser.close();
}

