// i18n/I18nProvider.tsx
'use client';
import { IntlMessageFormat } from '@formatjs/intl-messageformat';
import { createContext, useContext, useMemo, type ReactNode } from 'react';

type Messages = Record<string, string>;

type I18nContext = {
  locale: string;
  t: (key: string, values?: Record<string, string | number>) => string;
};

const Context = createContext<I18nContext | null>(null);

export function I18nProvider({
  locale,
  messages,
  children,
}: {
  locale: string;
  messages: Messages;
  children: ReactNode;
}) {
  const value = useMemo<I18nContext>(() => {
    const formatters = new Map<string, IntlMessageFormat>();
    return {
      locale,
      t(key, values) {
        const message = messages[key];
        if (!message) {
          if (process.env.NODE_ENV !== 'production') console.warn(`Missing: ${key}`);
          return key;
        }
        let fmt = formatters.get(key);
        if (!fmt) {
          fmt = new IntlMessageFormat(message, locale);
          formatters.set(key, fmt);
        }
        return fmt.format(values) as string;
      },
    };
  }, [locale, messages]);
  return <Context.Provider value={value}>{children}</Context.Provider>;
}

export function useTranslation() {
  const ctx = useContext(Context);
  if (!ctx) throw new Error('useTranslation outside I18nProvider');
  return ctx;
}

// Usage
export function Greeting({ name, messageCount, sender }: { name: string; messageCount: number; sender: string }) {
  const { t } = useTranslation();
  return (
    <div>
      <h1>{t('hello', { name })}</h1>
      <p>{t('messageFrom', { count: messageCount, sender })}</p>
      <p>{t('itemCount', { count: 0 })}</p>
    </div>
  );
}

// Loader for code splitting per locale
async function loadMessages(locale: string): Promise<Messages> {
  const mod = await import(`./locales/${locale}.json`);
  return mod.default;
}

// app/layout.tsx (Next.js)
export default async function Layout({ children, params }: { children: ReactNode; params: Promise<{ locale: string }> }) {
  const { locale } = await params;
  const messages = await loadMessages(locale);
  return (
    <html lang={locale} dir={['ar', 'he', 'fa'].includes(locale) ? 'rtl' : 'ltr'}>
      <body>
        <I18nProvider locale={locale} messages={messages}>
          {children}
        </I18nProvider>
      </body>
    </html>
  );
}

// i18n.ts
import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';
import ICU from 'i18next-icu';
import HttpBackend from 'i18next-http-backend';
import LanguageDetector from 'i18next-browser-languagedetector';

i18n
  .use(ICU)
  .use(HttpBackend)
  .use(LanguageDetector)
  .use(initReactI18next)
  .init({
    fallbackLng: 'en',
    supportedLngs: ['en', 'es', 'de', 'ja', 'ar', 'pl'],
    backend: { loadPath: '/locales/{{lng}}/{{ns}}.json' },
    interpolation: { escapeValue: false },
  });

export default i18n;

// App.tsx
import './i18n';
import { useTranslation } from 'react-i18next';

export function Greeting({ name, messageCount, sender }: { name: string; messageCount: number; sender: string }) {
  const { t, i18n: i } = useTranslation();
  return (
    <div dir={['ar', 'he'].includes(i.language) ? 'rtl' : 'ltr'}>
      <h1>{t('hello', { name })}</h1>
      <p>{t('messageFrom', { count: messageCount, sender })}</p>
      <p>{t('itemCount', { count: 0 })}</p>
    </div>
  );
}

// LanguageSwitch.tsx
import { useTranslation } from 'react-i18next';

export function LanguageSwitch() {
  const { i18n } = useTranslation();
  return (
    <select value={i18n.language} onChange={(e) => i18n.changeLanguage(e.target.value)}>
      {['en', 'es', 'de', 'ja', 'ar', 'pl'].map((lang) => (
        <option key={lang} value={lang}>{lang.toUpperCase()}</option>
      ))}
    </select>
  );
}
